type MediaLoadStatus =
  | { error: true }
  | { error: false; width: number; height: number };

const mediaLoadCache = new Map<
  string,
  Promise<MediaLoadStatus> | MediaLoadStatus
>();

const RESIZABLE_MEDIA_MAX_SIZE_MULTIPLIER = 2;

export const RIGHT_CLICK_MEDIA_COMMAND: LexicalCommand<MouseEvent> =
  createCommand('RIGHT_CLICK_MEDIA_COMMAND');

function DisableCaptionOnBlur({
  setShowCaption,
}: {
  setShowCaption: (show: boolean) => void;
}) {
  const [editor] = useLexicalComposerContext();
  useEffect(() =>
    editor.registerCommand(
      BLUR_COMMAND,
      () => {
        if ($isCaptionEditorEmpty()) {
          setShowCaption(false);
        }
        return false;
      },
      COMMAND_PRIORITY_EDITOR,
    ),
  );
  return null;
}

function useSuspenseImage(src: string): MediaLoadStatus {
  let cached = mediaLoadCache.get(src);
  if (cached && 'error' in cached && typeof cached.error === 'boolean') {
    return cached;
  } else if (!cached) {
    cached = new Promise<MediaLoadStatus>((resolve) => {
      const img = new Image();
      img.src = src;
      img.onload = () =>
        resolve({
          error: false,
          height: img.naturalHeight,
          width: img.naturalWidth,
        });
      img.onerror = () => resolve({ error: true });
    }).then((rval) => {
      mediaLoadCache.set(src, rval);
      return rval;
    });
    mediaLoadCache.set(src, cached);
    throw cached;
  }
  throw cached;
}

function isSVG(src: string): boolean {
  return src.toLowerCase().endsWith('.svg');
}

function LazyImage({
  altText,
  className,
  mediaRef,
  src,
  width,
  height,
  maxWidth,
  onError,
}: {
  altText: string;
  className: string | null;
  height: 'inherit' | number;
  mediaRef: (element: HTMLImageElement | null) => void;
  maxWidth: number;
  src: string;
  width: 'inherit' | number;
  onError: () => void;
}): JSX.Element {
  const isSVGImage = isSVG(src);
  const status = useSuspenseImage(src);

  useEffect(() => {
    if (status.error) {
      onError();
    }
  }, [status.error, onError]);

  if (status.error) {
    return <BrokenImage />;
  }

  // Calculate final dimensions with proper scaling
  const calculateDimensions = () => {
    if (!isSVGImage || !('width' in status) || !('height' in status)) {
      return {
        height,
        maxWidth,
        width,
      };
    }

    // Use natural dimensions if available, otherwise fallback to defaults
    const naturalWidth = status.width;
    const naturalHeight = status.height;

    let finalWidth = naturalWidth;
    let finalHeight = naturalHeight;

    // Scale down if width exceeds maxWidth while maintaining aspect ratio
    if (finalWidth > maxWidth) {
      const scale = maxWidth / finalWidth;
      finalWidth = maxWidth;
      finalHeight = Math.round(finalHeight * scale);
    }

    // Scale down if height exceeds maxHeight while maintaining aspect ratio
    const maxHeight = maxWidth;
    if (finalHeight > maxHeight) {
      const scale = maxHeight / finalHeight;
      finalHeight = maxHeight;
      finalWidth = Math.round(finalWidth * scale);
    }

    return {
      height: finalHeight,
      maxWidth,
      width: finalWidth,
    };
  };

  const imageStyle = calculateDimensions();

  return (
    <img
      className={className || undefined}
      src={src}
      alt={altText}
      ref={mediaRef}
      style={imageStyle}
      onError={onError}
      draggable="false"
    />
  );
}

function Video({
  altText,
  className,
  height,
  maxWidth,
  mediaRef,
  onError,
  src,
  width,
}: {
  altText: string;
  className: string | null;
  height: 'inherit' | number;
  maxWidth: number;
  mediaRef: (element: HTMLVideoElement | null) => void;
  onError: () => void;
  src: string;
  width: 'inherit' | number;
}): JSX.Element {
  return (
    <video
      className={className || undefined}
      src={src}
      title={altText}
      ref={mediaRef}
      style={{ height, maxWidth, width }}
      onError={onError}
      controls={true}
      draggable="false"
    />
  );
}

function Audio({
  altText,
  className,
  height,
  maxWidth,
  mediaRef,
  onError,
  src,
  width,
}: {
  altText: string;
  className: string | null;
  height: 'inherit' | number;
  maxWidth: number;
  mediaRef: (element: HTMLAudioElement | null) => void;
  onError: () => void;
  src: string;
  width: 'inherit' | number;
}): JSX.Element {
  return (
    <audio
      className={className || undefined}
      src={src}
      title={altText}
      ref={mediaRef}
      style={{
        height: height === 'inherit' ? undefined : height,
        maxWidth,
        width: width === 'inherit' ? maxWidth : width,
      }}
      onError={onError}
      controls={true}
      draggable="false"
    />
  );
}

function PdfPreview({
  altText,
  className,
  defaultWidth,
  height,
  maxWidth,
  mediaRef,
  src,
  width,
}: {
  altText: string;
  className: string | null;
  defaultWidth: number;
  height: 'inherit' | number;
  maxWidth: number;
  mediaRef: (element: HTMLIFrameElement | null) => void;
  src: string;
  width: 'inherit' | number;
}): JSX.Element {
  return (
    <iframe
      className={className || undefined}
      src={src}
      title={altText || 'PDF'}
      ref={mediaRef}
      style={{
        height: height === 'inherit' ? 500 : height,
        maxWidth,
        width: width === 'inherit' ? defaultWidth : width,
      }}
    />
  );
}

function BrokenImage(): JSX.Element {
  return (
    <img
      src={brokenImage}
      style={{
        height: 200,
        opacity: 0.2,
        width: 200,
      }}
      draggable="false"
      alt="Broken image"
    />
  );
}

function noop() {}

const MEDIA_DOWNLOAD_EXTENSION: Record<MediaType, string> = {
  audio: 'mp3',
  image: 'png',
  pdf: 'pdf',
  video: 'mp4',
};

function getMediaDownloadFileName(
  src: string,
  altText: string,
  mediaType: MediaType,
): string {
  const sourcePath = src.trim().split(/[?#]/)[0];

  if (sourcePath !== '' && !/^(?:blob|data):/i.test(sourcePath)) {
    const fileName = sourcePath.split(/[\\/]/).pop();

    if (fileName !== undefined && fileName.trim() !== '') {
      return fileName;
    }
  }

  const altTextFileName = altText.trim();

  return altTextFileName !== ''
    ? altTextFileName
    : `media.${MEDIA_DOWNLOAD_EXTENSION[mediaType]}`;
}

export default function MediaComponent({
  src,
  mediaType,
  previewSrc,
  altText,
  nodeKey,
  width,
  height,
  maxWidth,
  resizable,
  showCaption,
  caption,
  captionsEnabled,
}: {
  altText: string;
  caption: LexicalEditor;
  height: 'inherit' | number;
  maxWidth: number;
  mediaType: MediaType;
  nodeKey: NodeKey;
  previewSrc?: string;
  resizable: boolean;
  showCaption: boolean;
  src: string;
  width: 'inherit' | number;
  captionsEnabled: boolean;
}): JSX.Element {
  const mediaRef = useRef<null | HTMLElement>(null);
  const buttonRef = useRef<HTMLButtonElement | null>(null);
  const [isSelected, setSelected, clearSelection] =
    useLexicalNodeSelection(nodeKey);
  const [isResizing, setIsResizing] = useState<boolean>(false);
  const [storedPreviewSrc, setStoredPreviewSrc] = useState<
    string | undefined
  >();
  const { isCollabActive } = useCollaborationContext();
  const { revealFile } = useMediaFileActions();
  const [editor] = useLexicalComposerContext();
  const activeEditorRef = useRef<LexicalEditor | null>(null);
  const [isLoadError, setIsLoadError] = useState<boolean>(false);
  const isEditable = useLexicalEditable();
  const isInNodeSelection = useMemo(
    () =>
      isSelected &&
      editor.getEditorState().read(() => {
        const selection = $getSelection();
        return $isNodeSelection(selection) && selection.has(nodeKey);
      }),
    [editor, isSelected, nodeKey],
  );

  const $onEnter = useCallback(
    (event: KeyboardEvent) => {
      const latestSelection = $getSelection();
      const buttonElem = buttonRef.current;
      if (
        $isNodeSelection(latestSelection) &&
        latestSelection.has(nodeKey) &&
        latestSelection.getNodes().length === 1
      ) {
        if (showCaption) {
          // Move focus into nested editor
          $setSelection(null);
          event.preventDefault();
          caption.focus();
          return true;
        } else if (
          buttonElem !== null &&
          buttonElem !== document.activeElement
        ) {
          event.preventDefault();
          buttonElem.focus();
          return true;
        }
      }
      return false;
    },
    [caption, nodeKey, showCaption],
  );

  const $onEscape = useCallback(
    (event: KeyboardEvent) => {
      if (
        activeEditorRef.current === caption ||
        buttonRef.current === event.target
      ) {
        $setSelection(null);
        editor.update(() => {
          setSelected(true);
          const parentRootElement = editor.getRootElement();
          if (parentRootElement !== null) {
            parentRootElement.focus();
          }
        });
        return true;
      }
      return false;
    },
    [caption, editor, setSelected],
  );

  const $onDelete = useCallback(
    (event: KeyboardEvent) => {
      const latestSelection = $getSelection();
      if (!$isNodeSelection(latestSelection) || !latestSelection.has(nodeKey)) {
        return false;
      }

      let didRemove = false;
      for (const node of latestSelection.getNodes()) {
        if ($isMediaNode(node)) {
          node.remove();
          didRemove = true;
        }
      }

      if (didRemove) {
        event.preventDefault();
      }
      return didRemove;
    },
    [nodeKey],
  );

  const onClick = useCallback(
    (payload: MouseEvent) => {
      const event = payload;

      if (isResizing) {
        return true;
      }
      if (event.target === mediaRef.current) {
        if (mediaType === 'video' || mediaType === 'audio') {
          event.preventDefault();
        }
        if (event.shiftKey) {
          setSelected(!isSelected);
        } else {
          clearSelection();
          setSelected(true);
        }
        return true;
      }

      return false;
    },
    [isResizing, isSelected, mediaType, setSelected, clearSelection],
  );

  const onRightClick = useCallback(
    (event: MouseEvent): void => {
      editor.getEditorState().read(() => {
        const latestSelection = $getSelection();
        const domElement = event.target as HTMLElement;
        if (
          domElement === mediaRef.current &&
          $isRangeSelection(latestSelection) &&
          latestSelection.getNodes().length === 1
        ) {
          editor.dispatchCommand(RIGHT_CLICK_MEDIA_COMMAND, event);
        }
      });
    },
    [editor],
  );

  useEffect(() => {
    return mergeRegister(
      editor.registerCommand(
        SELECTION_CHANGE_COMMAND,
        (_, activeEditor) => {
          activeEditorRef.current = activeEditor;
          return false;
        },
        COMMAND_PRIORITY_LOW,
      ),
      editor.registerCommand(
        DRAGSTART_COMMAND,
        (event) => {
          if (event.target === mediaRef.current) {
            // TODO This is just a temporary workaround for FF to behave like other browsers.
            // Ideally, this handles drag & drop too (and all browsers).
            event.preventDefault();
            return true;
          }
          return false;
        },
        COMMAND_PRIORITY_LOW,
      ),
    );
  }, [editor]);

  useEffect(() => {
    setIsLoadError(false);
  }, [mediaType, previewSrc, src, storedPreviewSrc]);

  useEffect(() => {
    let isActive = true;
    let objectUrl: string | undefined;

    setStoredPreviewSrc(undefined);

    if (mediaType === 'image' || previewSrc) {
      return () => {
        isActive = false;
      };
    }

    void createStoredMediaPreviewSrc(src).then((nextPreviewSrc) => {
      if (!nextPreviewSrc) {
        return;
      }

      if (!isActive) {
        if (typeof URL.revokeObjectURL === 'function') {
          URL.revokeObjectURL(nextPreviewSrc);
        }
        return;
      }

      objectUrl = nextPreviewSrc;
      setStoredPreviewSrc(nextPreviewSrc);
    });

    return () => {
      isActive = false;

      if (objectUrl && typeof URL.revokeObjectURL === 'function') {
        URL.revokeObjectURL(objectUrl);
      }
    };
  }, [mediaType, previewSrc, src]);
  useEffect(() => {
    let rootCleanup = noop;
    return mergeRegister(
      editor.registerCommand<MouseEvent>(
        CLICK_COMMAND,
        onClick,
        COMMAND_PRIORITY_LOW,
      ),
      editor.registerCommand<MouseEvent>(
        RIGHT_CLICK_MEDIA_COMMAND,
        onClick,
        COMMAND_PRIORITY_LOW,
      ),
      editor.registerCommand(KEY_ENTER_COMMAND, $onEnter, COMMAND_PRIORITY_LOW),
      editor.registerCommand(
        KEY_DELETE_COMMAND,
        $onDelete,
        COMMAND_PRIORITY_LOW,
      ),
      editor.registerCommand(
        KEY_BACKSPACE_COMMAND,
        $onDelete,
        COMMAND_PRIORITY_LOW,
      ),
      editor.registerCommand(
        KEY_ESCAPE_COMMAND,
        $onEscape,
        COMMAND_PRIORITY_LOW,
      ),
      editor.registerRootListener((rootElement) => {
        rootCleanup();
        rootCleanup = noop;
        if (rootElement) {
          rootElement.addEventListener('contextmenu', onRightClick);
          rootCleanup = () =>
            rootElement.removeEventListener('contextmenu', onRightClick);
        }
      }),
      () => rootCleanup(),
    );
  }, [editor, $onDelete, $onEnter, $onEscape, onClick, onRightClick]);

  const setShowCaption = (show: boolean) => {
    editor.update(() => {
      const node = $getNodeByKey(nodeKey);
      if ($isMediaNode(node)) {
        node.setShowCaption(show);
        if (show) {
          node.__caption.update(() => {
            if (!$getSelection()) {
              $getRoot().selectEnd();
            }
          });
        }
      }
    });
  };

  const onResizeEnd = (
    nextWidth: 'inherit' | number,
    nextHeight: 'inherit' | number,
  ) => {
    // Delay hiding the resize bars for click case
    setTimeout(() => {
      setIsResizing(false);
    }, 200);

    editor.update(() => {
      const node = $getNodeByKey(nodeKey);
      if ($isMediaNode(node)) {
        node.setWidthAndHeight(nextWidth, nextHeight);
      }
    });
  };

  const onResizeStart = () => {
    setIsResizing(true);
  };

  const { historyState } = useSharedHistoryContext();
  const {
    settings: { showNestedEditorTreeView },
  } = useSettings();

  const draggable = isInNodeSelection && !isResizing;
  const isFocused = (isSelected || isResizing) && isEditable;
  const mediaClassName = isFocused
    ? `focused ${isInNodeSelection ? 'draggable' : ''}`
    : null;
  const supportsResize =
    mediaType === 'image' || mediaType === 'video' || mediaType === 'pdf';
  const resizableMediaMaxWidth = maxWidth * RESIZABLE_MEDIA_MAX_SIZE_MULTIPLIER;
  const setMediaRef = useCallback((element: HTMLElement | null) => {
    mediaRef.current = element;
  }, []);
  const mediaSource = previewSrc || storedPreviewSrc || src;
  const downloadFileName = getMediaDownloadFileName(src, altText, mediaType);
  const revealMediaFile =
    revealFile !== undefined && isRevealableFilePath(src) ? revealFile : null;
  const shouldShowMediaActions = isInNodeSelection && !isResizing;

  const mediaElement =
    mediaType === 'video' ? (
      <Video
        className={mediaClassName}
        src={mediaSource}
        altText={altText}
        mediaRef={setMediaRef}
        width={width}
        height={height}
        maxWidth={resizableMediaMaxWidth}
        onError={() => setIsLoadError(true)}
      />
    ) : mediaType === 'audio' ? (
      <Audio
        className={mediaClassName}
        src={mediaSource}
        altText={altText}
        mediaRef={setMediaRef}
        width={width}
        height={height}
        maxWidth={maxWidth}
        onError={() => setIsLoadError(true)}
      />
    ) : mediaType === 'pdf' ? (
      <PdfPreview
        className={mediaClassName}
        src={mediaSource}
        altText={altText}
        mediaRef={setMediaRef}
        width={width}
        height={height}
        defaultWidth={maxWidth}
        maxWidth={resizableMediaMaxWidth}
      />
    ) : (
      <LazyImage
        className={mediaClassName}
        src={src}
        altText={altText}
        mediaRef={setMediaRef}
        width={width}
        height={height}
        maxWidth={resizableMediaMaxWidth}
        onError={() => setIsLoadError(true)}
      />
    );
  const shouldShowBrokenImage = isLoadError && mediaType === 'image';

  return (
    <Suspense fallback={null}>
      <>
        <div draggable={draggable}>
          {shouldShowBrokenImage ? <BrokenImage /> : mediaElement}
        </div>

        {shouldShowMediaActions ? (
          <div
            className="media-floating-actions"
            role="toolbar"
            aria-label="Media options"
          >
            <a
              className="media-action-button"
              href={mediaSource}
              download={downloadFileName}
              title="Download media"
              aria-label="Download media"
              onClick={(event) => {
                event.stopPropagation();
              }}
            >
              <i className="bi bi-download" aria-hidden="true" />
            </a>
            {revealMediaFile !== null ? (
              <button
                className="media-action-button"
                type="button"
                title="Reveal media file"
                aria-label="Reveal media file"
                onClick={(event) => {
                  event.preventDefault();
                  event.stopPropagation();
                  void revealMediaFile(src);
                }}
              >
                <i className="bi bi-folder2-open" aria-hidden="true" />
              </button>
            ) : null}
          </div>
        ) : null}

        {showCaption && (
          <div className="media-caption-container">
            <LexicalNestedComposer initialEditor={caption}>
              <DisableCaptionOnBlur setShowCaption={setShowCaption} />
              <MentionNamePlugin />
              <MentionLocationsPlugin />
              <LinkPlugin />
              <EmojisPlugin />
              <KeywordsPlugin />
              {isCollabActive ? (
                <CollaborationPlugin
                  id={caption.getKey()}
                  providerFactory={createWebsocketProvider}
                  shouldBootstrap={true}
                />
              ) : (
                <HistoryPlugin externalHistoryState={historyState} />
              )}
              <RichTextPlugin
                contentEditable={
                  <ContentEditable
                    placeholder="Enter a caption..."
                    placeholderClassName="MediaNode__placeholder"
                    className="MediaNode__contentEditable"
                  />
                }
                ErrorBoundary={LexicalErrorBoundary}
              />
              {showNestedEditorTreeView === true ? <TreeViewPlugin /> : null}
            </LexicalNestedComposer>
          </div>
        )}
        {resizable && supportsResize && isInNodeSelection && isFocused && (
          <MediaResizer
            showCaption={showCaption}
            setShowCaption={setShowCaption}
            editor={editor}
            buttonRef={buttonRef}
            mediaRef={mediaRef}
            maxWidth={resizableMediaMaxWidth}
            onResizeStart={onResizeStart}
            onResizeEnd={onResizeEnd}
            captionsEnabled={!isLoadError && captionsEnabled}
          />
        )}
      </>
    </Suspense>
  );
}
